import Foundation

struct WidgetEntry {
    let date: Date
    let value: Int
}

func buildTimeline() -> [WidgetEntry] {
    let now = Date()
    return (0..<3).map { i in
        WidgetEntry(date: now.addingTimeInterval(Double(i) * 3600), value: i)
    }
}

let timeline = buildTimeline()
print(timeline.count)
